INSERT INTO `health_assessment_detail`(`system_score`,`gender`,`birth_date`,`abnormal_analysis`,`health_assessment_id`,`risk_level`,`physical_report_url`,`id`,`age`,`report_summary`) VALUES ('{"breathingSystem":100,"digestiveSystem":85,"endocrineSystem":90,"immuneSystem":95,"circulatorySystem":80,"urinarySystem":85,"motionSystem":95,"senseSystem":90}',1,'1946-09-01T00:00','[{"conclusion":"心率偏快","examinationItem":"心率","result":"92 次/分","referenceValue":"<90 次/分","unit":"次/分","interpret":"心率稍高于正常范围，可能与活动、情绪或潜在的心脏问题有关。","advice":"建议进行心电图检查及定期监测心率，如有必要，请咨询心脏科医生。"},{"conclusion":"轻度脂肪肝可能","examinationItem":"肝B超","result":"实质回声略粗糙","referenceValue":"回声均匀","unit":"-","interpret":"肝脏实质回声略粗糙，提示可能有轻度脂肪肝，这与饮食习惯、肥胖、酒精摄入等因素有关。","advice":"建议改善饮食习惯，减少高脂、高糖食物摄入，适量运动，并定期复查肝脏B超。"},{"conclusion":"慢性胆囊炎可能","examinationItem":"胆B超","result":"胆囊壁毛糙","referenceValue":"胆囊壁光滑","unit":"-","interpret":"胆囊壁毛糙可能提示慢性胆囊炎，这可能与胆囊结石、感染或长期不良饮食习惯有关。","advice":"建议进一步检查以明确诊断，并改善饮食习惯，避免油腻食物，如有症状请及时就医。"},{"conclusion":"脾轻度增大","examinationItem":"脾B超","result":"脾轻度增大","referenceValue":"脾脏大小正常","unit":"-","interpret":"脾脏轻度增大可能与感染、血液系统疾病或自身免疫性疾病有关。","advice":"建议进一步检查以明确原因，并定期监测脾脏大小变化。"},{"conclusion":"右肾小囊肿可能","examinationItem":"肾B超","result":"右肾下极见一大小约 5mm 的无回声区","referenceValue":"肾脏无异常回声","unit":"mm","interpret":"右肾小囊肿可能为单纯性肾囊肿，一般无需特殊处理，但需定期监测。","advice":"建议定期复查肾脏B超，观察囊肿变化，如有异常请及时就医。"},{"conclusion":"前列腺形态略增大","examinationItem":"前列腺B超","result":"形态略增大","referenceValue":"前列腺大小形态正常","unit":"-","interpret":"前列腺形态略增大可能与前列腺增生有关，这是老年男性常见疾病。","advice":"建议进行PSA检查以排除前列腺肿瘤可能，并定期监测前列腺大小变化。"}]',1,'提示','https://itheim.oss-cn-beijing.aliyuncs.com/132123194609011234.pdf',1,65,'体检报告中心率、肝脏B超、胆囊B超、脾脏B超、肾脏B超、前列腺B超共6项指标提示异常。综合这些临床指标和数据分析：循环系统、消化系统存在隐患，其中循环系统有“中危”风险；消化系统有“低危”风险。');
